INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-A01', 'Iniciar tarefa em até 2 minutos', 'Atenção e permanência em tarefa', 'P1', 'Reduzir a latência entre a instrução de início e o primeiro comportamento funcional alinhado à tarefa. Protocolo de entrada do Bloco A — trata especificamente o custo de ativação inicial.', '2.5', '{"protocol_id": "TDAH-A01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","latency_window_minutes": 2,"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-A02', 'Permanecer on-task por bloco curto', 'Atenção e permanência em tarefa', 'P1', 'Aumentar o engajamento funcional contínuo em blocos curtos de atividade acadêmica. Trabalha permanência após início — complementa A01 (início) e precede A05 (ampliação de tempo).', '2.5', '{"protocol_id": "TDAH-A02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","block_duration_minutes": 0,"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-A03', 'Retomar tarefa após distração', 'Atenção e permanência em tarefa', 'P1', 'Aumentar a capacidade de retornar à tarefa após distração/interrupção sem reinício completo ou redirecionamento excessivo. Foca em: reduzir tempo perdido após quebra, fortalecer retomada funcional, evitar que distração breve vire abandono total.', '2.5', '{"protocol_id": "TDAH-A03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","distraction_definition": "","return_window_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-A04', 'Completar atividade com divisão em passos', 'Atenção e permanência em tarefa', 'P1', 'Aumentar a probabilidade de conclusão de atividade por meio de divisão explícita em passos menores, sequenciais e mensuráveis. Reduzir sobrecarga diante de tarefas longas, aumentar visibilidade do progresso e fortalecer sustentação executiva.', '2.5', '{"protocol_id": "TDAH-A04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","expected_outcome": "","steps_count": 0,"functional_hypothesis": "","planned_antecedent": "","defined_reinforcement": "","main_context": ""}'::jsonb, true);

