VALUES ('TDAH-A05', 'Aumentar tempo de permanência progressiva', 'Atenção e permanência em tarefa', 'P1', 'Ampliar gradualmente a duração funcional de permanência em tarefa sem saltos bruscos de exigência. Expande blocos toleráveis com progressão realista, não força de resistência.', '2.5', '{"protocol_id": "TDAH-A05","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","base_duration_minutes": 0,"target_duration_minutes": 0,"functional_hypothesis": ""}'::jsonb, true);

