VALUES ('TDAH-A06', 'Reduzir evasão de demanda leve', 'Atenção e permanência em tarefa', 'P1', 'Reduzir microcomportamentos de fuga/evasão que comprometem início, manutenção ou conclusão de demandas funcionais — mesmo sem explosão comportamental. Transforma esquiva sutil em variável observável e tratável.', '2.5', '{"protocol_id": "TDAH-A06","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","evasion_definition": "","max_evasion_per_block": 1,"functional_hypothesis": ""}'::jsonb, true);

