VALUES ('TDAH-B01', 'Seguir instrução de 1 passo', 'Seguimento de instruções e rotina', 'P1', 'Estabelecer ou fortalecer o seguimento de instrução de passo único — base de toda a cadeia do Bloco B. Reduzir latência, repetição excessiva e dependência de escalada verbal.', '2.5', '{"protocol_id": "TDAH-B01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","instruction_type": "","latency_window_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

