VALUES ('TDAH-B02', 'Seguir instrução de 2 passos', 'Seguimento de instruções e rotina', 'P1', 'Ampliar resposta funcional de instrução unitária para cadeia curta de 2 passos. Reduzir perda do segundo elemento, diminuir repetição excessiva do adulto e fortalecer memória funcional imediata.', '2.5', '{"protocol_id": "TDAH-B02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_instruction": "","order_required": true,"time_window_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

