VALUES ('TDAH-B03', 'Completar rotina matinal com apoio visual', 'Seguimento de instruções e rotina', 'P1', 'Estruturar a rotina matinal como sequência funcional com apoio visual, reduzindo dependência de lembretes verbais, conflitos e atrasos recorrentes na preparação para sair.', '2.5', '{"protocol_id": "TDAH-B03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","morning_routine_steps": [],"visual_support_type": "","functional_hypothesis": ""}'::jsonb, true);

