VALUES ('TDAH-B04', 'Completar rotina de saída', 'Seguimento de instruções e rotina', 'P1', 'Organizar e estabilizar a etapa final da rotina de saída: reduzir atrasos, esquecimentos, dependência de múltiplos comandos e quebra da sequência entre estar em casa e efetivamente partir para o compromisso.', '2.5', '{"protocol_id": "TDAH-B04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","departure_steps": [],"essential_items": [],"functional_hypothesis": ""}'::jsonb, true);

