VALUES ('TDAH-B05', 'Completar rotina de dever', 'Seguimento de instruções e rotina', 'P1', 'Estruturar o dever de casa como rotina funcional previsível com começo, meio e fim claros. Reduzir postergação, conflito, evasão e abandono da tarefa acadêmica.', '2.5', '{"protocol_id": "TDAH-B05","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","homework_routine_steps": [],"completion_criterion": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-B06', 'Transitar entre atividades com menor resistência', 'Seguimento de instruções e rotina', 'P1', 'Reduzir resistência e desorganização na passagem entre atividades. Aumentar capacidade de encerrar ação atual e iniciar a seguinte com menor custo comportamental, menor atraso e menor intervenção do adulto.', '2.5', '{"protocol_id": "TDAH-B06","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","origin_activity": "","destination_activity": "","transition_time_criterion_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

