VALUES ('TDAH-C01', 'Reduzir interrupções verbais', 'Impulsividade e autocontrole', 'P1', 'Reduzir frequência de interrupções verbais impulsivas em contextos estruturados — sala de aula, atividade em grupo, refeição. Diferenciar impulsividade verbal de problemas pragmáticos ou ansiedade social.', '2.5', '{"protocol_id": "TDAH-C01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","max_interruptions_per_block": 0,"functional_hypothesis": ""}'::jsonb, true);

