VALUES ('TDAH-C02', 'Esperar a vez em contexto estruturado', 'Impulsividade e autocontrole', 'P1', 'Ensinar a aguardar a vez em atividades estruturadas com regra de turno clara — jogo, roda, fila, atividade em grupo — sem invasão de turno, sem protesto intenso e com comportamento compatível durante a espera.', '2.5', '{"protocol_id": "TDAH-C02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_activity": "","wait_time_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

