VALUES ('TDAH-C03', 'Pedir ajuda de forma adequada', 'Impulsividade e autocontrole', 'P1', 'Ensinar a substituir fuga, protesto, travamento silencioso ou interrupção inadequada por um pedido funcional, claro e socialmente adequado de ajuda. Criar alternativa funcional quando a criança não consegue avançar sozinha.', '2.5', '{"protocol_id": "TDAH-C03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","help_request_form": "","target_context": "","functional_hypothesis": ""}'::jsonb, true);

