VALUES ('TDAH-C04', 'Reduzir levantar do lugar sem permissão', 'Impulsividade e autocontrole', 'P1', 'Reduzir saídas motoras impulsivas e não funcionais do lugar em contextos estruturados. Aumentar permanência física compatível com a atividade, diferenciando necessidade real de movimento de quebra desorganizada do contexto.', '2.5', '{"protocol_id": "TDAH-C04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_context": "","max_exits_per_block": 1,"functional_hypothesis": ""}'::jsonb, true);

