VALUES ('TDAH-C05', 'Tolerar pequena espera com reforço planejado', 'Impulsividade e autocontrole', 'P1', 'Aumentar a capacidade de tolerar pequenas esperas em contextos funcionais, mantendo comportamento compatível até o acesso ao reforço, item, turno ou atividade previamente combinados. Treinar atraso pequeno, previsível e ligado a contingência clara.', '2.5', '{"protocol_id": "TDAH-C05","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_reinforcer": "","initial_wait_seconds": 0,"functional_hypothesis": ""}'::jsonb, true);

