VALUES ('TDAH-C06', 'Pausar antes de responder', 'Impulsividade e autocontrole', 'P1', 'Ensinar a inserir uma pausa funcional entre o estímulo e a resposta em situações de alta probabilidade de reação impulsiva. Reduzir respostas automáticas precipitadas e aumentar autorregulação pré-resposta.', '2.5', '{"protocol_id": "TDAH-C06","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_context": "","pause_form": "","functional_hypothesis": ""}'::jsonb, true);

