VALUES ('TDAH-D01', 'Organizar mochila/material', 'Organização e planejamento', 'P1', 'Construir rotina funcional e autônoma de organização da mochila e materiais escolares, reduzindo esquecimentos, dependência de supervisão adulta intensa e conflitos recorrentes ligados à preparação de material.', '2.5', '{"protocol_id": "TDAH-D01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","material_list": [],"fixed_time": "","functional_hypothesis": ""}'::jsonb, true);

