VALUES ('TDAH-D02', 'Usar checklist de tarefa', 'Organização e planejamento', 'P1', 'Ensinar o uso funcional e autônomo de checklist como andaime executivo. Reduzir dependência de instrução verbal do adulto e aumentar a capacidade de guiar execução de tarefa pela estrutura visual do checklist.', '2.5', '{"protocol_id": "TDAH-D02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","checklist_items": [],"functional_hypothesis": ""}'::jsonb, true);

