VALUES ('TDAH-D03', 'Iniciar pelo primeiro passo sem procrastinação extensa', 'Organização e planejamento', 'P1', 'Reduzir o tempo entre a instrução de início e o primeiro comportamento funcional alinhado à tarefa. Trabalhar especificamente o déficit de ativação — o custo de "entrar" na tarefa — não a continuidade em si.', '2.5', '{"protocol_id": "TDAH-D03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_task": "","first_step_definition": "","latency_window_minutes": 2,"functional_hypothesis": ""}'::jsonb, true);

