VALUES ('TDAH-D04', 'Finalizar tarefa antes de trocar de atividade', 'Organização e planejamento', 'P1', 'Treinar o fechamento funcional de tarefa antes de transitar para outra atividade. Combate a tendência de abandonar no meio ou trocar de atividade impulsivamente sem conclusão, criando padrão de "fechar antes de abrir".', '2.5', '{"protocol_id": "TDAH-D04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","closure_definition": "","functional_hypothesis": ""}'::jsonb, true);

