VALUES ('TDAH-E01', 'Implementar sistema de reforço doméstico', 'Regulação emocional e comportamental', 'P1', 'Estruturar sistema de reforço doméstico funcional, consistente e calibrado ao perfil da criança. Substituir dinâmicas de coerção/punição por contingências positivas claras que aumentem adesão e cooperação no cotidiano.', '2.5', '{"protocol_id": "TDAH-E01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","system_format": "","target_behaviors": [],"identified_reinforcers": [],"functional_hypothesis": ""}'::jsonb, true);

