VALUES ('TDAH-E02', 'Elogio específico e contingente', 'Regulação emocional e comportamental', 'P1', 'Treinar responsáveis e profissionais a usar elogio específico, contingente e funcional como reforçador social eficaz. Substituir elogios genéricos, atrasados ou desconectados do comportamento por resposta imediata e descritiva que fortaleça o comportamento-alvo.', '2.5', '{"protocol_id": "TDAH-E02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_behaviors": [],"praise_format": "","functional_hypothesis": ""}'::jsonb, true);

