VALUES ('TDAH-E03', 'Instrução objetiva e consistente', 'Regulação emocional e comportamental', 'P1', 'Treinar responsáveis e educadores a emitir instruções curtas, objetivas, afirmativas e consistentes. Reduzir sobrecarga verbal, comandos longos, repetições em cascata e negociações que comprometem o seguimento de instrução da criança com TDAH.', '2.5', '{"protocol_id": "TDAH-E03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_contexts": [],"instruction_format_trained": "","functional_hypothesis": ""}'::jsonb, true);

