VALUES ('TDAH-E04', 'Resposta planejada a não seguimento de regra', 'Regulação emocional e comportamental', 'P1', 'Treinar responsáveis a responder ao não seguimento de regra de forma planejada, calma e consistente — sem escalada emocional, sem ceder sob pressão e sem punição desproporcional. Substituir reatividade por protocolo.', '2.5', '{"protocol_id": "TDAH-E04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","non_compliance_situations": [],"planned_response": "","functional_hypothesis": ""}'::jsonb, true);

