VALUES ('TDAH-F04', 'DRC de seguir instruções do professor', 'Habilidades sociais e comunicação', 'P1', 'DRC focado em seguimento de instruções do professor em sala de aula. Objetivar a queixa "não obedece" em dado registrável e comunicável, criando loop escola-família-clínica funcional.', '2.5', '{"protocol_id": "TDAH-F04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","instruction_criterion": "","home_reinforcer": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-F05', 'DRC de organização escolar', 'Habilidades sociais e comunicação', 'P1', 'DRC focado em organização de material e rotina escolar. Cria dado objetivo sobre cadernos, material, mesa e itens escolares para monitoramento família-escola com intervenção clínica articulada.', '2.5', '{"protocol_id": "TDAH-F05","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","organization_criterion": "","home_reinforcer": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-F06', 'Plano escola-casa com reforço cruzado', 'Habilidades sociais e comunicação', 'P1', 'Coordenar contingências entre escola e casa para comportamentos-alvo que dependem de continuidade entre contextos. Vai além do DRC simples — cria plano integrado com reforço cruzado (escola registra → casa reforça → clínica monitora).', '2.5', '{"protocol_id": "TDAH-F06","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","school_target": "","home_reinforcer": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G01', 'Reconhecer sinal inicial de desregulação', 'Suporte regulatório e AuDHD', 'P1', 'Ensinar a identificar sinais corporais e comportamentais precoces de desregulação emocional — antes da explosão ou ruptura. Criar janela de intervenção antes que o ciclo escape ao controle. Pré-condição para G02 e toda a sequência de regulação.', '2.5', '{"protocol_id": "TDAH-G01","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","personal_signals_map": [],"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G02', 'Solicitar pausa de forma funcional', 'Suporte regulatório e AuDHD', 'P1', 'Ensinar a comunicar necessidade de pausa regulatória antes de atingir ponto de ruptura, usando forma previamente combinada, funcional e compreensível para os adultos do contexto. Criar alternativa funcional à explosão ou fuga desorganizada.', '2.5', '{"protocol_id": "TDAH-G02","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","pause_signal_form": "","adults_trained": [],"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G03', 'Usar recurso visual para retorno à tarefa', 'Suporte regulatório e AuDHD', 'P1', 'Ensinar o uso de recurso visual (cartão, checklist, marcador) como andaime concreto para retornar à tarefa após pausa ou distração. Reduzir dependência de instrução verbal do adulto para reorientação.', '2.5', '{"protocol_id": "TDAH-G03","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","visual_resource_type": "","target_task": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G04', 'Tolerar mudança pequena com previsibilidade', 'Suporte regulatório e AuDHD', 'P1', 'Aumentar a tolerância a pequenas variações esperadas na rotina ou tarefa, por meio de antecipação, previsibilidade e exposição gradual calibrada. Reduzir reação excessiva a mudanças mínimas que perturbam o funcionamento cotidiano.', '2.5', '{"protocol_id": "TDAH-G04","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","target_variation": "","advance_notice_minutes": 0,"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G05', 'Modular demanda com reforço diferencial', 'Suporte regulatório e AuDHD', 'P1', 'Ajustar nível e formato da demanda de forma sistemática, combinado com reforço diferencial, para reduzir custo comportamental do engajamento e aumentar cooperação funcional. Usa calibração de demanda como variável clínica — não como cedência.', '2.5', '{"protocol_id": "TDAH-G05","version": "2.5","audhd_layer_status": "off | active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","demand_modulation": "","differential_reinforcement": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G06', 'Plano combinado para sensorialidade + tarefa', 'Suporte regulatório e AuDHD', 'P1', 'Criar plano integrado que combina suporte sensorial com estrutura de tarefa para crianças com perfil AuDHD nas quais a permanência, o início ou a conclusão da tarefa são fortemente impactados por sobrecarga sensorial, necessidade de regulação prévia ou alta vulnerabilidade a estímulos concorrentes.', '2.5', '{"protocol_id": "TDAH-G06","version": "2.5","audhd_layer_status": "active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","sensory_support": [],"task_structure": [],"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G08', 'Reduzir atrito em transição entre demandas', 'Suporte regulatório e AuDHD', 'P1.1', 'Reduzir o custo comportamental e regulatório de transições entre demandas diferentes, com atenção especial ao perfil AuDHD onde a rigidez executiva e o custo de mudança de estado são fatores centrais — não apenas impulsividade ou "birra".', '2.5', '{"protocol_id": "TDAH-G08","version": "2.5","audhd_layer_status": "active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","demand_origin": "","demand_destination": "","anticipation_resource": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G10', 'Ajustar rotina sob sobrecarga sensorial previsível', 'Suporte regulatório e AuDHD', 'P1.1', 'Ensinar a antecipar e ajustar funcionamento em dias/períodos com sobrecarga sensorial previsível — antes que o acúmulo leve à desregulação. Intervenção proativa, não apenas reativa.', '2.5', '{"protocol_id": "TDAH-G10","version": "2.5","audhd_layer_status": "active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","sensory_contexts_mapped": [],"planned_adjustments": [],"functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G11', 'Manejo de custo adaptativo invisível', 'Suporte regulatório e AuDHD', 'P1.1', 'Reconhecer e manejar o custo regulatório oculto do mascaramento adaptativo (camouflage/masking) — esforço invisível de adequação social que drena recursos regulatórios e precipita desregulação tardia. Protocolo central no perfil AuDHD.', '2.5', '{"protocol_id": "TDAH-G11","version": "2.5","audhd_layer_status": "active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","collapse_pattern": "","decompression_strategy": "","post_context_demand_reduction": "","functional_hypothesis": ""}'::jsonb, true);

INSERT INTO tdah_protocol_library (code, title, block, priority, description, bible_version, system_fields, is_active)
VALUES ('TDAH-G12', 'Regulação pós-esforço adaptativo', 'Suporte regulatório e AuDHD', 'P1.1', 'Estruturar estratégias e rotinas de recuperação regulatória após períodos de esforço adaptativo intenso. Fecha a sequência G10 → G11 → G12: sobrecarga previsível → custo acumulado → regulação pós-esforço.', '2.5', '{"protocol_id": "TDAH-G12","version": "2.5","audhd_layer_status": "active_core | active_full","snapshot_type": "initial | progress | closure","source_record_id": "","restorative_activities": [],"recovery_window_minutes": 0,"demanding_contexts": [],"functional_hypothesis": ""}'::jsonb, true);

